#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void random_matrix(float *I, int rows, int cols);

static inline void cuda_check(cudaError_t err, const char *msg) {
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA error at %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

void usage(int argc, char **argv)
{
    (void)argc;
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1> \t - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

    exit(1);
}

__global__ void srad_cuda_1(const float *J, float *dN, float *dS, float *dW, float *dE,
                            float *c, int rows, int cols,
                            const int *iN, const int *iS, const int *jW, const int *jE,
                            float q0sqr)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;
        float Jc = J[k];

        dN[k] = J[iN[i] * cols + j] - Jc;
        dS[k] = J[iS[i] * cols + j] - Jc;
        dW[k] = J[i * cols + jW[j]] - Jc;
        dE[k] = J[i * cols + jE[j]] - Jc;

        float G2 = (dN[k] * dN[k] + dS[k] * dS[k] +
                    dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);

        float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

        float num = (float)((0.5 * G2) - ((1.0 / 16.0) * (L * L)));
        float den = (float)(1 + (.25 * L));
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
        c[k] = 1.0f / (1.0f + den);

        if (c[k] < 0) c[k] = 0;
        else if (c[k] > 1) c[k] = 1;
    }
}

__global__ void srad_cuda_2(float *J, const float *c, const float *dN, const float *dS,
                            const float *dW, const float *dE,
                            int rows, int cols, const int *iS, const int *jE, float lambda)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;

        float cN = c[k];
        float cS = c[iS[i] * cols + j];
        float cW = c[k];
        float cE = c[i * cols + jE[j]];

        float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

        J[k] = J[k] + (float)(0.25 * lambda * D);
    }
}

int main(int argc, char* argv[])
{
    int rows, cols, size_I, size_R, niter = 10, iter, k;
    float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
    int *iN, *iS, *jE, *jW;
    float *dN, *dS, *dW, *dE;
    int r1, r2, c1, c2;
    float *c;
    float lambda;
    int i, j;
    int nthreads;

    if (argc == 10)
    {
        rows = atoi(argv[1]);
        cols = atoi(argv[2]);
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = atoi(argv[3]);
        r2 = atoi(argv[4]);
        c1 = atoi(argv[5]);
        c2 = atoi(argv[6]);
        nthreads = atoi(argv[7]);
        lambda = (float)atof(argv[8]);
        niter = atoi(argv[9]);
    }
    else {
        usage(argc, argv);
    }

    (void)nthreads;

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    if (I == NULL) {
        fprintf(stderr, "malloc failed\n");
        exit(1);
    }

    cuda_check(cudaMallocManaged(&J, size_I * sizeof(float)), "cudaMallocManaged(J)");
    cuda_check(cudaMallocManaged(&c, size_I * sizeof(float)), "cudaMallocManaged(c)");
    cuda_check(cudaMallocManaged(&iN, rows * sizeof(int)), "cudaMallocManaged(iN)");
    cuda_check(cudaMallocManaged(&iS, rows * sizeof(int)), "cudaMallocManaged(iS)");
    cuda_check(cudaMallocManaged(&jW, cols * sizeof(int)), "cudaMallocManaged(jW)");
    cuda_check(cudaMallocManaged(&jE, cols * sizeof(int)), "cudaMallocManaged(jE)");
    cuda_check(cudaMallocManaged(&dN, size_I * sizeof(float)), "cudaMallocManaged(dN)");
    cuda_check(cudaMallocManaged(&dS, size_I * sizeof(float)), "cudaMallocManaged(dS)");
    cuda_check(cudaMallocManaged(&dW, size_I * sizeof(float)), "cudaMallocManaged(dW)");
    cuda_check(cudaMallocManaged(&dE, size_I * sizeof(float)), "cudaMallocManaged(dE)");

    for (int ii = 0; ii < rows; ii++) {
        iN[ii] = ii - 1;
        iS[ii] = ii + 1;
    }
    for (int jj = 0; jj < cols; jj++) {
        jW[jj] = jj - 1;
        jE[jj] = jj + 1;
    }
    iN[0] = 0;
    iS[rows - 1] = rows - 1;
    jW[0] = 0;
    jE[cols - 1] = cols - 1;

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }

    printf("Start the SRAD main loop\n");

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

    for (iter = 0; iter < niter; iter++) {
        sum = 0;
        sum2 = 0;
        for (i = r1; i <= r2; i++) {
            for (j = c1; j <= c2; j++) {
                tmp = J[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        srad_cuda_1<<<grid, block>>>(J, dN, dS, dW, dE, c, rows, cols, iN, iS, jW, jE, q0sqr);
        cuda_check(cudaGetLastError(), "srad_cuda_1 launch");
        cuda_check(cudaDeviceSynchronize(), "srad_cuda_1 sync");

        srad_cuda_2<<<grid, block>>>(J, c, dN, dS, dW, dE, rows, cols, iS, jE, lambda);
        cuda_check(cudaGetLastError(), "srad_cuda_2 launch");
        cuda_check(cudaDeviceSynchronize(), "srad_cuda_2 sync");
    }

#ifdef OUTPUT
    for (int ii = 0; ii < rows; ii++) {
        for (int jj = 0; jj < cols; jj++) {
            printf("%.5f ", J[ii * cols + jj]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    free(I);
    cudaFree(J);
    cudaFree(iN);
    cudaFree(iS);
    cudaFree(jW);
    cudaFree(jE);
    cudaFree(dN);
    cudaFree(dS);
    cudaFree(dW);
    cudaFree(dE);
    cudaFree(c);

    return 0;
}

